import { execSync } from 'node:child_process'
import { writeFileSync } from 'node:fs'
import { resolve } from 'node:path'
import dotenv from 'dotenv'

const statusOutput = execSync('supabase status -o env', { encoding: 'utf-8' })
const status = dotenv.parse(statusOutput)

const lines = [
  '# Generated by pnpm db:env — do not commit',
  `NEXT_PUBLIC_SUPABASE_URL=${status.API_URL}`,
  `NEXT_PUBLIC_SUPABASE_ANON_KEY=${status.ANON_KEY}`,
  `SUPABASE_SERVICE_ROLE_KEY=${status.SERVICE_ROLE_KEY}`,
  'NEXT_PUBLIC_APP_URL=http://localhost:3000',
  'NEXT_PUBLIC_OAUTH_GOOGLE_ENABLED=false',
  'NEXT_PUBLIC_OAUTH_GITHUB_ENABLED=false',
  '',
]

const envPath = resolve(process.cwd(), '.env.local')
writeFileSync(envPath, lines.join('\n'), 'utf-8')
console.log(`Wrote ${envPath}`)
